const body=document.getElementsByTagName('BODY')[0];function id(a){return document.getElementById(a)}function cl(a){return document.getElementsByClassName(a)}function closeFilterBox(){id('toc-box').style.display="none",id('table-of-content').style.height="auto",body.style.overflow="unset"}function filterBox(){id('open-categories').addEventListener('click',a=>{id('toc-box').style.display=="block"?(id('toc-box').style.display="none",id('table-of-content').style.height="auto"):(id('toc-box').style.display="block",body.style.overflow="hidden",id('table-of-content').style.height="-webkit-fill-available")}),id('table-of-content').addEventListener('click',a=>{closeFilterBox()})}function hideAllCard(){for(let a=0;a<cl('dropdown').length;a++)cl('dropdown')[a].classList.add('hide')}function showAllCard(){for(let a=0;a<cl('dropdown').length;a++)cl('dropdown')[a].classList.remove('hide')}function cardBtnHide(){for(let a=0;a<cl('card-act').length;a++)cl('card-act')[a].classList.add('hide')}function cardBtnShow(){for(let a=0;a<cl('card-act').length;a++)cl('card-act')[a].classList.remove('hide')}function filterCat(){for(let a=0;a<cl('sidebar-filter').length;a++)cl('sidebar-filter')[a].addEventListener('click',c=>{closeFilterBox();let b=cl('sidebar-filter')[a].getAttribute('data-show');b=='all'?(showAllCard(),cardBtnShow()):(hideAllCard(),cardBtnHide(),id(b).classList.remove('hide'))})}function allcardDropdown(){for(let a=0;a<cl('action-drop').length;a++)cl('action-drop')[a].addEventListener('click',c=>{let b=cl('action-drop')[a].getAttribute('data-dropdown');id(b+"-dropdown").classList.toggle('hide'),cl('action-drop')[a].classList.toggle('close')})}screen.width<960&&(filterBox(),filterCat(),allcardDropdown())